import { loadMicroFrontend } from './utils/micro-frontend-loader';

export function ShellApp() {
  const [currentRoute, setCurrentRoute] = useState('/');

  const loadApp = async (route: string) => {
    switch (route) {
      case '/products':
        return await loadMicroFrontend('product-app');
      case '/cart':
        return await loadMicroFrontend('cart-app');
      case '/checkout':
        return await loadMicroFrontend('checkout-app');
    }
  };

  return (
    <div>
      <Navigation />
      <main>
        {loadApp(currentRoute)}
      </main>
    </div>
  );
}

// utils/micro-frontend-loader.ts
export async function loadMicroFrontend(appName: string) {
  const script = document.createElement('script');
  script.src = `https://cdn.example.com/${appName}/main.js`;
  document.head.appendChild(script);

  return new Promise((resolve) => {
    script.onload = () => {
      // Micro-frontend carregado
      resolve(window[appName]);
    };
  });
}
